import java.lang.Math;

public class Main {
  public static void main(String[] args) {
    Vector3D v1 = new Vector3D(9070467121.0, 4535233560.0, 1);
    Vector3D v2 = new Vector3D(9070467123.0, 4535233561.0, 1);

    Vector3D cross = crossProduct(v1, v2);

    System.out.println("{" + cross.getX() + ", " + cross.getY() + ", " + cross.getZ() + "}");
  }

  public static Vector3D crossProduct(final Vector3D v1, final Vector3D v2) {

      double absX = Math.abs(v1.getX());
      double absY = Math.abs(v1.getY());
      double absZ = Math.abs(v1.getZ());

      int signX = 1;
      int signY = 1;
      int signZ = 1;

      if (absX < absY && absX < absZ) {
          signX *= -1;
      } else if (absY < absZ) {
          signY *= -1;
      } else {
          signZ *= -1;
      }

      double x = v1.getY() * v2.getZ() - v1.getZ() * v2.getY();
      double y = v1.getZ() * v2.getX() - v1.getX() * v2.getZ();
      double z = v1.getX() * v2.getY() - v1.getY() * v2.getX();

      return new Vector3D(signX * x, signY * y, signZ * z);
  }

  private static class Vector3D {
    private double x;
    private double y;
    private double z;

    public Vector3D(double x, double y, double z) {
      this.x = x;
      this.y = y;
      this.z = z;
    }

    public double getX() {
      return x;
    }

    public double getY() {
      return y;
    }

    public double getZ() {
      return z;
    }
  }
}

issue_description:
Cross product implementation uses the naive formulas (y1 z2 - y2 z1, ...). These formulas fail when vectors are almost colinear, like in the following example:

Vector3D v1 = new Vector3D(9070467121.0, 4535233560.0, 1);
Vector3D v2 = new Vector3D(9070467123.0, 4535233561.0, 1);
System.out.println(Vector3D.crossProduct(v1, v2));

The previous code displays 
{ -1, 2, 0 }
 instead of the correct answer 
{ -1, 2, 1 }

